description:
The function called when the context menu has been shown.<note>If a plugin is listening for this event, it must call the {@link /plugin/executeMethod/common/addcontextmenuitem AddContextMenuItem} method (synchronously or not),because the editor waits for responses from all plugins before filling the context menu.</note>

## Try it

 ```js document-builder={"documentType": "common"}
window.Asc.plugin.attachEvent('onContextMenuShow', function(options) {
	if (!options) return;

	if (options.type === 'Selection' || options.type === 'Target')
		this.executeMethod('AddContextMenuItem', [getContextMenuItems()]);
});
```

example:
```js
window.Asc.plugin.attachEvent('onContextMenuShow', function(options) {
	if (!options) return;

	if (options.type === 'Selection' || options.type === 'Target')
		this.executeMethod('AddContextMenuItem', [getContextMenuItems()]);
});
```

description:
The function called when the context menu item has been clicked.

## Try it

 ```js document-builder={"documentType": "common"}
window.Asc.plugin.event_onContextMenuClick = function(id)
{
    var pluginObj = window.Asc.plugin;
    var itemId = id;
    var itemData = undefined;
    var itemPos = itemId.indexOf("_oo_sep_");
    if (-1 !== itemPos)
    {
        itemData = itemId.substring(itemPos + 8);
        itemId = itemId.substring(0, itemPos);
    }

    if (pluginObj.contextMenuEvents && pluginObj.contextMenuEvents[itemId])
        pluginObj.contextMenuEvents[itemId].call(pluginObj, itemData);
};
```

